-- ============================================================
-- Migration 000071: Idempotent seed of default email templates
--                   and communication rules for all tenants.
--
-- 1. Add UNIQUE(tenant_id, name) to email_templates (deduplicate first)
-- 2. Upsert all 9 default templates for every existing tenant
-- 3. Insert default rules where none exist yet (per event_type)
-- ============================================================

-- ── 1. Unique constraint ──────────────────────────────────────────
DO $$
BEGIN
  -- Remove duplicates: keep the most recently created row per tenant+name
  WITH ranked AS (
    SELECT id,
           ROW_NUMBER() OVER (PARTITION BY tenant_id, name ORDER BY created_at DESC) AS rn
    FROM public.email_templates
  )
  DELETE FROM public.email_templates WHERE id IN (SELECT id FROM ranked WHERE rn > 1);

  ALTER TABLE public.email_templates
    ADD CONSTRAINT email_templates_tenant_name_unique UNIQUE (tenant_id, name);
EXCEPTION WHEN duplicate_object THEN NULL;
END;
$$;

-- ── 2. Seed templates (upsert by tenant+name) ─────────────────────
CREATE TEMP TABLE _tmpl (
  tname TEXT, tsubject TEXT, tbody TEXT, tvars TEXT[]
) ON COMMIT DROP;

