 ARRAY['client_name','gym_name','login_url']);

-- Upsert templates for all tenants
INSERT INTO public.email_templates (tenant_id, name, subject, body_html, variables)
SELECT t.id, dt.tname, dt.tsubject, dt.tbody, dt.tvars
FROM public.tenants t CROSS JOIN _tmpl dt
ON CONFLICT (tenant_id, name) DO UPDATE
  SET subject    = EXCLUDED.subject,
      body_html  = EXCLUDED.body_html,
      variables  = EXCLUDED.variables,
      updated_at = NOW();

-- ── 3. Seed default communication rules ──────────────────────────
-- One rule per event_type per tenant, only if no rule exists yet.
INSERT INTO public.communication_rules (tenant_id, name, event_type, template_id, recipients, is_active)
SELECT
  t.id,
  rules.rule_name,
  rules.event_type,
  et.id,
  rules.recipients,
  true
FROM public.tenants t
CROSS JOIN (VALUES
  ('Notificación de cita creada',      'appointment.created',    'Cita creada — pendiente de confirmación', 'client_and_coach'),
  ('Notificación de cita confirmada',  'appointment.confirmed',  'Cita confirmada',                         'client_and_coach'),
  ('Notificación de cita cancelada',   'appointment.cancelled',  'Cita cancelada',                          'client_and_coach'),
  ('Recordatorio de cita 30 min',      'appointment.reminder',   'Recordatorio de cita',                    'client'),
  ('Comprobante de plan adquirido',    'plan.purchased',         'Plan adquirido',                          'client'),
  ('Aviso de plan por vencer',         'plan.expiring',          'Plan por vencer',                         'client'),
  ('Notificación de plan vencido',     'plan.expired',           'Plan vencido',                            'client'),
  ('Cuenta aprobada',                  'client.approved',        'Cuenta aprobada',                         'client'),
  ('Email de bienvenida',              'client.welcome',         'Bienvenida al cliente',                   'client')
) AS rules(rule_name, event_type, template_name, recipients)
JOIN public.email_templates et
  ON et.tenant_id = t.id AND et.name = rules.template_name
WHERE NOT EXISTS (
  SELECT 1 FROM public.communication_rules cr
  WHERE cr.tenant_id = t.id AND cr.event_type = rules.event_type
);
